import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.DjqkqlVQ.js";const u=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/sts2-god-mod/faq.md","filePath":"en/mods/sts2-god-mod/faq.md","lastUpdated":1778341931000}'),r={name:"en/mods/sts2-god-mod/faq.md"};function n(s,e,d,l,h,c){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="what-is-god-mod-for" tabindex="-1">What is God Mod for? <a class="header-anchor" href="#what-is-god-mod-for" aria-label="Permalink to &quot;What is God Mod for?&quot;">​</a></h2><p>God Mod is a utility and cheat-style mod for Slay the Spire 2. It is designed for testing, sandbox play, build experiments, and faster run setup.</p><h2 id="is-it-intended-for-normal-progression" tabindex="-1">Is it intended for normal progression? <a class="header-anchor" href="#is-it-intended-for-normal-progression" aria-label="Permalink to &quot;Is it intended for normal progression?&quot;">​</a></h2><p>No. It directly changes game state, so it is best used for testing, experimentation, reproduction, or sandbox play.</p><h2 id="how-do-i-open-the-panel" tabindex="-1">How do I open the panel? <a class="header-anchor" href="#how-do-i-open-the-panel" aria-label="Permalink to &quot;How do I open the panel?&quot;">​</a></h2><p>Click the floating <code>G</code> button or hold the <code>G</code> hotkey.</p><h2 id="which-resources-can-it-edit" tabindex="-1">Which resources can it edit? <a class="header-anchor" href="#which-resources-can-it-edit" aria-label="Permalink to &quot;Which resources can it edit?&quot;">​</a></h2><p>It can edit gold, current HP, max HP, energy, and potion slots. It can also add, fill, or clear potions.</p><h2 id="how-powerful-is-card-editing" tabindex="-1">How powerful is card editing? <a class="header-anchor" href="#how-powerful-is-card-editing" aria-label="Permalink to &quot;How powerful is card editing?&quot;">​</a></h2><p>You can add, remove, duplicate, transform, upgrade, downgrade, enchant, keyword-edit, and stat-edit cards. Custom deck presets are also supported.</p><h2 id="does-it-support-relic-management" tabindex="-1">Does it support relic management? <a class="header-anchor" href="#does-it-support-relic-management" aria-label="Permalink to &quot;Does it support relic management?&quot;">​</a></h2><p>Yes. You can add or remove relics and apply quick relic bundles.</p><h2 id="what-can-it-do-in-combat" tabindex="-1">What can it do in combat? <a class="header-anchor" href="#what-can-it-do-in-combat" aria-label="Permalink to &quot;What can it do in combat?&quot;">​</a></h2><p>It can apply or remove statuses, fully heal, refill energy, clear debuffs, kill all enemies, control draw/discard, and spawn enemies.</p><h2 id="can-it-jump-into-events" tabindex="-1">Can it jump into events? <a class="header-anchor" href="#can-it-jump-into-events" aria-label="Permalink to &quot;Can it jump into events?&quot;">​</a></h2><p>Yes. It can jump directly into selected events during a run, which is useful for testing event branches and rewards.</p><h2 id="is-multiplayer-safe" tabindex="-1">Is multiplayer safe? <a class="header-anchor" href="#is-multiplayer-safe" aria-label="Permalink to &quot;Is multiplayer safe?&quot;">​</a></h2><p>God Mod changes a large amount of game state. Singleplayer testing and sandbox use are the recommended use cases. If you use it in multiplayer, only enable it in test sessions where all players agree.</p><h2 id="will-it-support-more-languages" tabindex="-1">Will it support more languages? <a class="header-anchor" href="#will-it-support-more-languages" aria-label="Permalink to &quot;Will it support more languages?&quot;">​</a></h2><p>That is planned. The current foundation supports English and Simplified Chinese, with future targets including Traditional Chinese, Japanese, Korean, Russian, Spanish, and Brazilian Portuguese.</p><h2 id="can-it-be-redistributed" tabindex="-1">Can it be redistributed? <a class="header-anchor" href="#can-it-be-redistributed" aria-label="Permalink to &quot;Can it be redistributed?&quot;">​</a></h2><p>Please do not reupload this mod, include it in paid packs, or redistribute edited versions without permission.</p>',23)])])}const m=a(r,[["render",n]]);export{u as __pageData,m as default};
